89	    @Test
90	    void assertDecodeWithStatusCode255() {
91	        ByteBuf byteBuf = Unpooled.buffer();
92	        byteBuf.writeByte(255);
93	        byteBuf.writeShortLE(123);
94	        byteBuf.writeByte(0);
95	        byteBuf.writeBytes("ABCDE".getBytes(StandardCharsets.UTF_8));
96	        byteBuf.writeBytes("errorMessage".getBytes(StandardCharsets.UTF_8));
