156	    @Test
157	    void assertDecodeWriteRowEvent() {
158	        ByteBuf byteBuf = ByteBufAllocator.DEFAULT.buffer();
159	        // the hex data is from INSERT INTO t_order(order_id, user_id, status, t_numeric) VALUES (1, 1, 'SUCCESS',null);
160	        byteBuf.writeBytes(StringUtil.decodeHexDump("007a36a9621e0100000038000000bb7c000000007b00000000000100020004ff08010000000000000001000000075355434345535365eff9ff"));
161	        byteBuf.writeBytes(StringUtil.decodeHexDump("006acb656410010000001f000000fa29000000001643000000000000b13f8340"));
162	        binlogContext.getTableMap().put(123L, tableMapEventPacket);
163	        when(tableMapEventPacket.getColumnDefs()).thenReturn(columnDefs);
