168	        assertThat(actualEventList.get(0), isA(MySQLWriteRowsBinlogEvent.class));
169	        MySQLWriteRowsBinlogEvent actual = (MySQLWriteRowsBinlogEvent) actualEventList.get(0);
170	        assertThat(actual.getAfterRows().get(0), is(new Serializable[]{1L, 1, new MySQLBinaryString("SUCCESS".getBytes()), null}));
171	    }
