173	    @Test
174	    void assertDecodeUpdateRowEvent() {
175	        ByteBuf byteBuf = ByteBufAllocator.DEFAULT.buffer();
176	        // the hex data is from update t_order set status = 'updated' where order_id = 1;
177	        byteBuf.writeBytes(StringUtil.decodeHexDump("00cb38a9621f010000004e0000000c7e000000007b00000000000100020004ffff08010000000000000001000000075355434345535308010000000000000001000000077570"
178	                + "6461746564e78cee6c"));
