192	    @Test
193	    void assertBinlogEventBodyIncomplete() {
194	        ByteBuf byteBuf = ByteBufAllocator.DEFAULT.buffer();
195	        byte[] completeData = StringUtil.decodeHexDump("002a80a862200100000038000000c569000000007400000000000100020004ff0801000000000000000100000007535543434553531c9580c5");
196	        byteBuf.writeBytes(completeData);
197	        byteBuf.writeBytes(StringUtil.decodeHexDump("006acb656410010000001f000000fa29000000001643000000000000b13f8340"));
198	        byte[] notCompleteData = StringUtil.decodeHexDump("00cb38a962130100000041000000be7d000000007b000000000001000464735f310009745f6f726465725f31000408030f");
199	        byteBuf.writeBytes(notCompleteData);
