207	    @Test
208	    void assertDecodePlaceholderEventSkipRemainBytes() {
209	        binlogContext.setFileName("binlog.000001");
210	        ByteBuf byteBuf = createPlaceholderEventByteBuf(MySQLBinlogEventType.UNKNOWN_EVENT.getValue(), MySQLBinlogEventHeader.MYSQL_BINLOG_EVENT_HEADER_LENGTH + 11, 7);
211	        List<Object> decodedEvents = new LinkedList<>();
