221	        ByteBuf byteBuf = createPlaceholderEventByteBuf(MySQLBinlogEventType.UNKNOWN_EVENT.getValue(), MySQLBinlogEventHeader.MYSQL_BINLOG_EVENT_HEADER_LENGTH, 0);
222	        List<Object> decodedEvents = new LinkedList<>();
