228	    @Test
229	    void assertProcessBeginQueryWithTX() throws NoSuchFieldException, IllegalAccessException {
230	        List<MySQLBaseBinlogEvent> existingRecords = new LinkedList<>();
231	        existingRecords.add(new PlaceholderBinlogEvent("binlog.000003", 1L, 1L));
232	        Plugins.getMemberAccessor().set(MySQLBinlogEventPacketDecoder.class.getDeclaredField("records"), binlogEventPacketDecoder, existingRecords);
233	        ByteBuf byteBuf = createQueryEventByteBuf("BEGIN", binlogContext.getChecksumLength());
234	        List<Object> decodedEvents = new LinkedList<>();
235	        binlogEventPacketDecoder.decode(channelHandlerContext, byteBuf, decodedEvents);
236	        assertTrue(decodedEvents.isEmpty());
237	        @SuppressWarnings("unchecked")
238	        List<MySQLBaseBinlogEvent> records = (List<MySQLBaseBinlogEvent>) Plugins.getMemberAccessor().get(MySQLBinlogEventPacketDecoder.class.getDeclaredField("records"), binlogEventPacketDecoder);
239	        assertTrue(records.isEmpty());
240	        assertThat(records, not(existingRecords));
241	    }
242	    
243	    @Test
244	    void assertDecodeWithoutTXSkipBeginQuery() {
245	        MySQLBinlogEventPacketDecoder decoderWithoutTX = new MySQLBinlogEventPacketDecoder(4, new ConcurrentHashMap<>(), false);
246	        ByteBuf beginEvent = createQueryEventByteBuf("BEGIN", 4);
247	        List<Object> decodedEvents = new LinkedList<>();
248	        decoderWithoutTX.decode(channelHandlerContext, beginEvent, decodedEvents);
249	        assertTrue(decodedEvents.isEmpty());
250	        ByteBuf queryEvent = createQueryEventByteBuf("SELECT 1", 4);
251	        decoderWithoutTX.decode(channelHandlerContext, queryEvent, decodedEvents);
252	        assertThat(decodedEvents.size(), is(1));
253	        assertThat(decodedEvents.get(0), isA(MySQLQueryBinlogEvent.class));
254	    }
255	    
256	    @Test
257	    void assertDecodeFormatDescriptionEventWithZeroChecksumAndExtraBytes() {
258	        MySQLBinlogEventPacketDecoder decoderWithoutChecksum = new MySQLBinlogEventPacketDecoder(0, new ConcurrentHashMap<>(), true);
259	        ByteBuf byteBuf = createFormatDescriptionEventByteBuf(4);
260	        decoderWithoutChecksum.decode(channelHandlerContext, byteBuf, new LinkedList<>());
261	        assertThat(byteBuf.readableBytes(), is(0));
262	        ByteBuf byteBufWithWarning = createFormatDescriptionEventByteBuf(3);
263	        decoderWithoutChecksum.decode(channelHandlerContext, byteBufWithWarning, new LinkedList<>());
264	        assertThat(byteBufWithWarning.readableBytes(), is(0));
265	    }
266	    
267	    private ByteBuf createPlaceholderEventByteBuf(final int eventType, final int eventSize, final int bodyLength) {
268	        ByteBuf result = Unpooled.buffer();
269	        result.writeByte(0);
270	        result.writeIntLE(1);
271	        result.writeByte(eventType);
272	        result.writeIntLE(1);
273	        result.writeIntLE(eventSize);
274	        result.writeIntLE(0);
275	        result.writeShortLE(0);
276	        result.writeZero(bodyLength);
277	        result.writeZero(binlogContext.getChecksumLength());
278	        return result;
279	    }
280	    
281	    private ByteBuf createQueryEventByteBuf(final String sql, final int checksumLength) {
282	        ByteBuf result = Unpooled.buffer();
283	        byte[] databaseBytes = "db".getBytes(StandardCharsets.UTF_8);
284	        byte[] sqlBytes = sql.getBytes(StandardCharsets.UTF_8);
285	        int bodyLength = 4 + 4 + 1 + 2 + 2 + databaseBytes.length + 1 + sqlBytes.length;
286	        int eventSize = MySQLBinlogEventHeader.MYSQL_BINLOG_EVENT_HEADER_LENGTH + bodyLength + checksumLength;
287	        result.writeByte(0);
288	        result.writeIntLE(1);
289	        result.writeByte(MySQLBinlogEventType.QUERY_EVENT.getValue());
290	        result.writeIntLE(1);
291	        result.writeIntLE(eventSize);
292	        result.writeIntLE(0);
293	        result.writeShortLE(0);
294	        result.writeIntLE(1);
295	        result.writeIntLE(2);
296	        result.writeByte(databaseBytes.length);
297	        result.writeShortLE(0);
298	        result.writeShortLE(0);
299	        result.writeBytes(databaseBytes);
300	        result.writeByte(0);
301	        result.writeBytes(sqlBytes);
302	        result.writeZero(checksumLength);
303	        return result;
304	    }
305	    
306	    private ByteBuf createFormatDescriptionEventByteBuf(final int extraBytesLength) {
307	        ByteBuf result = Unpooled.buffer();
308	        int bodyLength = 2 + 50 + 4 + 1 + (MySQLBinlogEventType.FORMAT_DESCRIPTION_EVENT.getValue() - 1) + 1 + 1 + extraBytesLength;
309	        int checksumLength = 0;
310	        int eventSize = MySQLBinlogEventHeader.MYSQL_BINLOG_EVENT_HEADER_LENGTH + bodyLength + checksumLength;
311	        result.writeByte(0);
312	        result.writeIntLE(1);
313	        result.writeByte(MySQLBinlogEventType.FORMAT_DESCRIPTION_EVENT.getValue());
314	        result.writeIntLE(1);
315	        result.writeIntLE(eventSize);
316	        result.writeIntLE(0);
317	        result.writeShortLE(0);
318	        result.writeShortLE(4);
319	        result.writeZero(50);
320	        result.writeIntLE(0);
321	        result.writeByte(MySQLBinlogEventHeader.MYSQL_BINLOG_EVENT_HEADER_LENGTH);
322	        result.writeZero(MySQLBinlogEventType.FORMAT_DESCRIPTION_EVENT.getValue() - 1);
323	        result.writeByte(72);
324	        result.writeZero(0);
325	        result.writeByte(0);
326	        result.writeZero(extraBytesLength);
327	        result.writeZero(checksumLength);
328	        return result;
329	    }
