124	        List<Object[]> nestedEntries = Collections.singletonList(new Object[]{JsonValueTypes.INT32, nestedKey, 111});
125	        ByteBuf payload = mockJsonObjectByteBuf(Collections.singletonList(new Object[]{nestedType, "subJson", nestedEntries}), isSmall);
126	        assertThat(MySQLJsonValueDecoder.decode(payload), is(expected));
127	    }
