            }
            index--;
        }
        for (int i = 0; i < index; i++) {
            lengthData[i] |= 0x80;
        }
        byte[] result = new byte[index + 1];
        System.arraycopy(lengthData, 0, result, 0, index + 1);
        return result;
    }

